for (int i = 0; i < n; ++i)
    for (int j = 0; j < m; ++j) if (g[i][j] == 'F') {
        dist[i][j] = 0;
        q.push({i, j});
    }
int dx[] = {-1, 0, 1, 0}, dy[] = {0, 1, 0, -1};
