// Rerooting: tổng khoảng cách từ mỗi đỉnh
vector<long long> f(n + 1);
vector<int> sz(n + 1, 1);
// DFS1: tính sz[] và f[1]
function<void(int,int,int)> dfs1 = [&](int u, int p, int d) {
    f[1] += d;
    for (int v : adj[u]) if (v != p) {
        dfs1(v, u, d + 1);
        sz[u] += sz[v];
    }
};
dfs1(1, 0, 0);
// DFS2: rerooting
function<void(int,int)> dfs2 = [&](int u, int p) {
    for (int v : adj[u]) if (v != p) {
        f[v] = f[u] - sz[v] + (n - sz[v]);
        dfs2(v, u);
    }
};
dfs2(1, 0);

