// Template cho 1 bài mock exam
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);
    if (fopen("BAI1.INP", "r")) {
        freopen("BAI1.INP", "r", stdin);
        freopen("BAI1.OUT", "w", stdout);
    }
    int n, K; cin >> n >> K;
    vector<int> a(n);
    for (auto &x : a) cin >> x;
    vector<long long> cnt(K, 0);
    for (int x : a) cnt[((x % K) + K) % K]++;
    long long ans = cnt[0] * (cnt[0] - 1) / 2;
    for (int r = 1; r < K; ++r) {
        if (r + r == K) ans += cnt[r] * (cnt[r] - 1) / 2;
        else if (r + r < K) ans += cnt[r] * cnt[K - r];
    }
    cout << ans << '\n';
    return 0;
}
